  function submitTuition(event){event.preventDefault();var id=$('tuitionId').value,plan=feeById($('tuitionPlan').value),row={id:id||uid('period'),studentId:$('tuitionStudent').value,subjectId:$('tuitionSubject').value,teacherId:$('tuitionTeacher').value,planId:plan.id,periodNo:numberOf($('tuitionPeriodNo').value)||1,startDate:$('tuitionStartDate').value,expiryDate:$('tuitionExpiryDate').value,lessonCount:numberOf($('tuitionLessonCount').value)||plan.lessonCount,expectedAmount:numberOf($('tuitionAmount').value),discount:numberOf($('tuitionDiscount').value),usedCount:id?periodById(id).usedCount:0,status:'active',note:$('tuitionNote').value.trim(),transactions:id?(periodById(id).transactions||[]):[],planSnapshot:clone(plan)};if(!row.studentId||!row.subjectId||!row.planId){toast('資料未完成','請選擇學生、科目與收費方案。','error');return;}if(id)Object.assign(periodById(id),row);else state.tuitionPeriods.push(row);save('學費期別已儲存');closeModal('tuitionModal');if(currentStudentId){studentTab='tuition';renderStudentModal();}renderStudents();toast('學費期別已建立','方案名稱、金額、堂數、拆帳與請假規則已保存快照。');}

  function openTransaction(periodId){if(!writable('新增付款或退款'))return;$('transactionForm').reset();$('transactionPeriodId').value=periodId;$('transactionDate').value=todayKey();openModal('transactionModal');}
